import{c as t,Q as i,j as o,m as a}from"./chunks/framework.BXc4yaFE.js";const h=JSON.parse('{"title":"Harness Engineering Best Practices for Claude Code / Codex Users, Explained Plainly","description":"","frontmatter":{"title":"Harness Engineering Best Practices for Claude Code / Codex Users, Explained Plainly","date":"2026-03-01T00:00:00.000Z","type":"article"},"headers":[],"relativePath":"research/ai-articles/scored/2026-03-01-harness-engineering-best-practices-2026-nyosegawa.md","filePath":"research/ai-articles/scored/2026-03-01-harness-engineering-best-practices-2026-nyosegawa.md","lastUpdated":1779796674000}'),s={name:"research/ai-articles/scored/2026-03-01-harness-engineering-best-practices-2026-nyosegawa.md"};function n(r,e,l,c,d,p){return i(),o("div",null,[...e[0]||(e[0]=[a(`<blockquote><p>Source: <a href="https://nyosegawa.com/en/posts/harness-engineering-best-practices-2026/" target="_blank" rel="noreferrer">https://nyosegawa.com/en/posts/harness-engineering-best-practices-2026/</a> Fetched: 2026-05-08</p></blockquote><h1 id="harness-engineering-best-practices-for-claude-code-codex-users-explained-plainly" tabindex="-1">Harness Engineering Best Practices for Claude Code / Codex Users, Explained Plainly <a class="header-anchor" href="#harness-engineering-best-practices-for-claude-code-codex-users-explained-plainly" aria-label="Permalink to &quot;Harness Engineering Best Practices for Claude Code / Codex Users, Explained Plainly&quot;">​</a></h1><h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h2><p>Harness engineering represents the systems and tools that enable coding agents to operate autonomously with minimal human oversight. Rather than focusing on model capabilities alone, this comprehensive guide emphasizes that &quot;the system, not the model, is what matters.&quot;</p><h2 id="what-is-harness-engineering" tabindex="-1">What is Harness Engineering? <a class="header-anchor" href="#what-is-harness-engineering" aria-label="Permalink to &quot;What is Harness Engineering?&quot;">​</a></h2><p>Harness engineering encompasses continuous improvement of agent instruction files and the toolchain enabling self-verification. The field exists to stabilize agent output and maintain autonomous operation. As noted in the original definition by Mitchell Hashimoto, this involves both human-driven AGENTS.md refinement and automated quality verification systems.</p><p>The guide acknowledges this field may have limited longevity—perhaps a few months to a year before LLM improvements reduce the need for such extensive scaffolding. However, for March 2026, it remains essential.</p><h2 id="core-principles" tabindex="-1">Core Principles <a class="header-anchor" href="#core-principles" aria-label="Permalink to &quot;Core Principles&quot;">​</a></h2><h3 id="_1-repository-hygiene-design-for-rot" tabindex="-1">1. Repository Hygiene: Design for Rot <a class="header-anchor" href="#_1-repository-hygiene-design-for-rot" aria-label="Permalink to &quot;1. Repository Hygiene: Design for Rot&quot;">​</a></h3><p>Agents treat all repository text equally, lacking intuition about document staleness. This necessitates careful curation of what lives in version control.</p><p><strong>What belongs in repos:</strong></p><ul><li>Executable artifacts (code, tests, linter configs, type definitions)</li><li>Architecture Decision Records (ADRs) with timestamps and status tracking</li></ul><p><strong>What doesn&#39;t belong:</strong></p><ul><li>Prose explanations of current system state</li><li>Handwritten API descriptions</li><li>Textual architecture overviews</li></ul><p>Tests provide superior resilience compared to documentation. When specifications become tests, they fail loudly upon breaking rather than rotting silently. This principle demands higher test coverage in agent-assisted development than human-only scenarios.</p><p>ADRs work well because their immutable structure—with explicit timestamps and status fields—allows agents to structurally determine currency. A superseded ADR remains identifiable through metadata rather than requiring subjective judgment.</p><h3 id="_2-enforce-quality-with-deterministic-tools-and-architectural-guardrails" tabindex="-1">2. Enforce Quality with Deterministic Tools and Architectural Guardrails <a class="header-anchor" href="#_2-enforce-quality-with-deterministic-tools-and-architectural-guardrails" aria-label="Permalink to &quot;2. Enforce Quality with Deterministic Tools and Architectural Guardrails&quot;">​</a></h3><p><strong>Core principle:</strong> &quot;LLMs are expensive and slow compared to traditional linters and formatters. Whenever a deterministic tool can do the job, use it.&quot;</p><p>This represents perhaps the most important distinction between prompt-based instruction and mechanical enforcement. Writing &quot;run the linter&quot; in CLAUDE.md differs fundamentally from executing linters through automated hooks—the former achieves success &quot;almost every time,&quot; while the latter ensures compliance &quot;every time without exception.&quot;</p><h4 id="hooks-system" tabindex="-1">Hooks System <a class="header-anchor" href="#hooks-system" aria-label="Permalink to &quot;Hooks System&quot;">​</a></h4><p>Claude Code Hooks are shell commands or prompts executing automatically at specific lifecycle points (PreToolUse, PostToolUse, Stop, PreCompact). The quality feedback loop follows this pattern:</p><ol><li>Agent writes code</li><li>PostToolUse hook automatically runs linters</li><li>Errors return as structured JSON within <code>hookSpecificOutput.additionalContext</code></li><li>Agent self-corrects without human intervention</li><li>Loop repeats on each file write</li></ol><p>The critical detail: returning plain stdout doesn&#39;t inject feedback. Proper JSON structure with <code>hookSpecificOutput.additionalContext</code> is required.</p><h4 id="four-hook-patterns" tabindex="-1">Four Hook Patterns <a class="header-anchor" href="#four-hook-patterns" aria-label="Permalink to &quot;Four Hook Patterns&quot;">​</a></h4><ul><li><strong>Safety Gates (PreToolUse):</strong> Block destructive commands (<code>rm -rf</code>, <code>drop table</code>) and prevent editing sensitive files</li><li><strong>Quality Loops (PostToolUse):</strong> Auto-run linters after file edits, injecting results as context for self-correction</li><li><strong>Completion Gates (Stop):</strong> Verify with tests before allowing agent completion</li><li><strong>Observability:</strong> Stream intent and results to monitoring systems</li></ul><h4 id="linter-selection-by-language" tabindex="-1">Linter Selection by Language <a class="header-anchor" href="#linter-selection-by-language" aria-label="Permalink to &quot;Linter Selection by Language&quot;">​</a></h4><p><strong>TypeScript/JavaScript:</strong> Oxlint (50–100x faster than ESLint) combined with Biome (10–25x faster than Prettier) for PostToolUse Hooks. ESLint remains valuable for custom architectural rules in pre-commit hooks and CI.</p><p><strong>Python:</strong> Ruff combines functionality of Flake8, isort, pyupgrade, pydocstyle, and Black into a single Rust-based binary with 900+ rules. PostToolUse Hook execution completes in under one second.</p><p><strong>Go:</strong> golangci-lint runs 50+ linters in parallel with robust caching. The <code>--fix</code> flag supports auto-fixes across 35 linters.</p><p><strong>Rust:</strong> Enable pedantic clippy with structural denial of <code>allow_attributes</code> to prevent agents from silencing lints via annotations.</p><h4 id="custom-linter-strategies-for-ai-code" tabindex="-1">Custom Linter Strategies for AI Code <a class="header-anchor" href="#custom-linter-strategies-for-ai-code" aria-label="Permalink to &quot;Custom Linter Strategies for AI Code&quot;">​</a></h4><p>Factory.ai categorizes agent-facing lint rules into four categories:</p><ul><li><strong>Grep-ability:</strong> Prefer named exports and consistent error types to improve hit rates during codebase searches</li><li><strong>Glob-ability:</strong> Keep file structure predictable for reliable placement and refactoring</li><li><strong>Architecture boundaries:</strong> Block cross-layer imports, enforce dependency direction</li><li><strong>Security/privacy:</strong> Prevent plaintext secrets, mandate input validation, forbid <code>eval</code></li></ul><p>Error messages should include not just violations but fix instructions. The pattern:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ERROR: [what is wrong] [file:line]</span></span>
<span class="line"><span>WHY: [why this rule exists, link to ADR]</span></span>
<span class="line"><span>FIX: [concrete fix steps with code example]</span></span></code></pre></div><h4 id="linter-config-protection" tabindex="-1">Linter Config Protection <a class="header-anchor" href="#linter-config-protection" aria-label="Permalink to &quot;Linter Config Protection&quot;">​</a></h4><p>Prevent agents from editing linter configurations to suppress errors instead of fixing code. PreToolUse hooks can block writes to <code>.eslintrc</code>, <code>pyproject.toml</code>, and similar files with clear error messages directing agents to fix the underlying code.</p><h4 id="feedback-speed-determines-quality" tabindex="-1">Feedback Speed Determines Quality <a class="header-anchor" href="#feedback-speed-determines-quality" aria-label="Permalink to &quot;Feedback Speed Determines Quality&quot;">​</a></h4><p>Quality correlates directly with feedback speed:</p><ul><li><strong>ms (PostToolUse Hook):</strong> Formatter auto-run—agent finishes fixing before recognizing the violation</li><li><strong>s (Pre-commit hook):</strong> Linter/type check prevents commit</li><li><strong>min (CI/CD):</strong> Full test suite catches issues before merge</li><li><strong>h+ (Human review):</strong> Slowest layer</li></ul><p>Push checks toward faster layers. Move CI-only linters into pre-commit hooks, move pre-commit checks into PostToolUse Hooks.</p><h3 id="_3-design-agents-md-claude-md-as-a-pointer" tabindex="-1">3. Design AGENTS.md / CLAUDE.md as a Pointer <a class="header-anchor" href="#_3-design-agents-md-claude-md-as-a-pointer" aria-label="Permalink to &quot;3. Design AGENTS.md / CLAUDE.md as a Pointer&quot;">​</a></h3><p>This file should function as a navigation map rather than a comprehensive manual.</p><p><strong>What to include:</strong></p><ul><li>Routing instructions (&quot;run <code>npm test</code>&quot;, &quot;ADRs live in <code>/docs/adr/</code>&quot;)</li><li>Prohibitions with ADR references</li><li>Minimum build/test/deploy commands</li></ul><p><strong>What to exclude:</strong></p><ul><li>System state explanations (code and tests are authoritative)</li><li>Tech stack descriptions (packages.json or go.mod reveal these)</li><li>Verbose style guides (delegate to linters)</li></ul><p><strong>Size target:</strong> Under 50 lines. The official recommendation of &quot;under 200 lines&quot; represents an upper bound, not a target. Research shows that at 150–200 instructions, primacy bias becomes pronounced and performance degrades.</p><p>Claude Code&#39;s system prompt contains approximately 50 instructions. A 100-line CLAUDE.md creates roughly 150 total instructions—approaching the degradation threshold. Compress aggressively.</p><p>Pointer-style design offers a benefit: broken references fail loudly (404-equivalent), making rot mechanically detectable.</p><h3 id="_4-separate-planning-from-execution" tabindex="-1">4. Separate Planning from Execution <a class="header-anchor" href="#_4-separate-planning-from-execution" aria-label="Permalink to &quot;4. Separate Planning from Execution&quot;">​</a></h3><p>Agents attempting all work simultaneously waste effort and lose architectural control. The workflow: agent produces plan → human approves → execution begins.</p><p>Agents naturally attempt &quot;one-shot&quot; completion of entire features. Explicit instruction to work on single features prevents this. Task decomposition into small building blocks with verification after each completes produces better results with minimal token usage.</p><p>Requiring end-to-end test verification before declaring completion dramatically improves accuracy. Agents often skip this without explicit instruction.</p><h3 id="_5-e2e-test-strategy-give-agents-eyes" tabindex="-1">5. E2E Test Strategy: Give Agents &quot;Eyes&quot; <a class="header-anchor" href="#_5-e2e-test-strategy-give-agents-eyes" aria-label="Permalink to &quot;5. E2E Test Strategy: Give Agents &quot;Eyes&quot;&quot;">​</a></h3><p>Without observability into code execution, agents declare work &quot;done&quot; upon compilation success. Browser automation tools and similar mechanisms provide agents the same verification vantage as human users.</p><h4 id="web-app-testing" tabindex="-1">Web App Testing <a class="header-anchor" href="#web-app-testing" aria-label="Permalink to &quot;Web App Testing&quot;">​</a></h4><p><strong>Playwright MCP (Microsoft official):</strong> Accessibility-tree-based interaction via role/name. Works across all major agents. <a href="https://shipyard.build/blog/playwright-agents-claude-code/" target="_blank" rel="noreferrer">Playwright v1.56+ ships three subagents</a> (Planner, Generator, Healer) for test generation and maintenance.</p><p>Limitation: MCP context tax is severe. Full accessibility tree snapshots consume significant tokens, with typical tasks consuming ~114,000 tokens and long sessions showing degradation.</p><p><strong>Playwright CLI:</strong> Same foundation, driven via shell commands rather than MCP protocol. Approximately 4x more token-efficient (~27,000 tokens for equivalent tasks). Accessibility snapshots store to filesystem rather than context window.</p><p><strong>agent-browser (Vercel Labs):</strong> Most token-efficient option. Element references (<code>@e1</code>, <code>@e2</code>) avoid CSS selector fragility. For 6 tests, Playwright MCP consumes ~31K characters while agent-browser consumes ~5.5K (5.7x improvement).</p><p>Recommendation by use case:</p><ul><li>Self-test loop: agent-browser or Playwright CLI</li><li>Test suite generation: Playwright MCP + subagents</li><li>Exploratory testing: agent-browser</li></ul><h4 id="universal-principle-the-accessibility-tree" tabindex="-1">Universal Principle: The Accessibility Tree <a class="header-anchor" href="#universal-principle-the-accessibility-tree" aria-label="Permalink to &quot;Universal Principle: The Accessibility Tree&quot;">​</a></h4><p>Both Playwright MCP and agent-browser interact via the accessibility tree—structured text rather than screenshots. This enables deterministic interaction, direct element manipulation by role/name, and CI assertions without coordinate guessing.</p><p><strong>Accessibility tree vs. screenshots:</strong></p><p>Use accessibility trees for:</p><ul><li>Programmatic interaction (form fills, navigation, clicks)</li><li>Deterministic testing (same output every time)</li><li>Operation automation</li></ul><p>Use screenshots for:</p><ul><li>Visual bug detection (layout, CSS, overlapping elements)</li><li>Visual regression testing</li><li>Rich content (canvas, charts, maps)</li><li>Spatial positioning and responsive behavior</li></ul><h4 id="mobile-app-testing" tabindex="-1">Mobile App Testing <a class="header-anchor" href="#mobile-app-testing" aria-label="Permalink to &quot;Mobile App Testing&quot;">​</a></h4><p>Xcode 26.3 introduced native MCP support, enabling agents to generate and run XCTest autonomously. For iOS, agent-driven E2E testing moved from experimental to production-ready.</p><p>Recommended tools:</p><ul><li><strong>iOS (Xcode 26.3):</strong> XcodeBuildMCP returns build errors as structured JSON</li><li><strong>iOS Simulator:</strong> iOS Simulator MCP Server via Facebook&#39;s IDB</li><li><strong>iOS/Android:</strong> mobile-mcp uses native accessibility tree</li><li><strong>React Native:</strong> Detox (gray-box testing) monitors async operations to prevent flakes</li><li><strong>Prototypes:</strong> Maestro MCP (YAML scripts, lightweight)</li></ul><p>Follow the generate-then-execute pattern: produce tests via MCP tools, then run generated XCTest/Detox/Espresso deterministically in CI.</p><h4 id="cli-tui-testing" tabindex="-1">CLI / TUI Testing <a class="header-anchor" href="#cli-tui-testing" aria-label="Permalink to &quot;CLI / TUI Testing&quot;">​</a></h4><p>bats-core (Bash Automated Testing System) is well-suited. TAP-compliant output integrates easily with CI. Each test runs in isolated process preventing state leakage.</p><p>Move script logic into <code>run_main</code> function and wrap with <code>if [[ &quot;\${BASH_SOURCE[0]}&quot; == &quot;\${0}&quot; ]]; then run_main; fi</code> to allow bats sourcing and function testing.</p><p>Use pexpect/expect for interactive CLIs handling prompts, timeouts, and password input programmatically.</p><h4 id="api-backend-testing" tabindex="-1">API / Backend Testing <a class="header-anchor" href="#api-backend-testing" aria-label="Permalink to &quot;API / Backend Testing&quot;">​</a></h4><p><strong>Hurl:</strong> Plain-text HTTP request definition with assertions. Lightweight Rust binary pairs well with agents. Generated Hurl files execute deterministically in CI.</p><p><strong>Pact:</strong> Contract testing for microservices. Pact v4.0.0 improved GraphQL support and async message handling.</p><p><strong>grpcurl:</strong> curl equivalent for gRPC services. Good for CLI-based smoke tests.</p><p><strong>Testcontainers:</strong> Spin up test database containers, automating migrate → seed → test → destroy cycles.</p><h4 id="desktop-app-testing" tabindex="-1">Desktop App Testing <a class="header-anchor" href="#desktop-app-testing" aria-label="Permalink to &quot;Desktop App Testing&quot;">​</a></h4><p><strong>Electron:</strong> Playwright&#39;s <code>_electron.launch()</code> supports Electron v12.2.0+ with full Page API access. <a href="https://github.com/microsoft/playwright-mcp" target="_blank" rel="noreferrer">Official Playwright MCP</a> has Electron support in development.</p><p><strong>Tauri:</strong> WebDriver interface on Windows/Linux. macOS has no official support (no WebDriver for WKWebView). Third-party solutions like tauri-webdriver and tauri-plugin-mcp fill this gap.</p><p><strong>Native apps:</strong> <a href="https://testdriver.ai/" target="_blank" rel="noreferrer">TestDriver.ai</a> uses fine-tuned AI understanding UIs from screenshots. Hardware emulation drives mouse/keyboard. Supports oauth flows and browser extensions.</p><h4 id="infrastructure-devops-testing" tabindex="-1">Infrastructure/DevOps Testing <a class="header-anchor" href="#infrastructure-devops-testing" aria-label="Permalink to &quot;Infrastructure/DevOps Testing&quot;">​</a></h4><ul><li><strong>Terraform:</strong> <code>terraform test</code> (native framework, v1.6+) plus Conftest + OPA for policy enforcement</li><li><strong>Docker:</strong> container-structure-test validates image structure via YAML/JSON</li><li><strong>Kubernetes:</strong> kubeconform schema-validates manifests; Conftest applies OPA policies</li></ul><p>Essential guardrails:</p><ul><li>Block direct production <code>terraform apply</code> or <code>kubectl apply</code> with PreToolUse hooks</li><li>Require passing <code>terraform test</code>, <code>conftest test</code>, and <code>kubeconform</code> via Stop hook</li><li>Pipe <code>terraform plan</code> through Conftest for policy validation before application</li></ul><h4 id="ai-ml-pipeline-testing" tabindex="-1">AI/ML Pipeline Testing <a class="header-anchor" href="#ai-ml-pipeline-testing" aria-label="Permalink to &quot;AI/ML Pipeline Testing&quot;">​</a></h4><p>Testing spans six layers:</p><ul><li><strong>Data quality:</strong> Great Expectations, dbt Tests, Soda Core</li><li><strong>Model evaluation:</strong> lm-evaluation-harness, LightEval</li><li><strong>Application quality (LLM):</strong> DeepEval, promptfoo, RAGAS</li><li><strong>Agent evaluation:</strong> LangSmith, Arize Phoenix, Langfuse</li><li><strong>Safety/guardrails:</strong> PyRIT, Guardrails AI, NeMo Guardrails</li><li><strong>Observability/drift:</strong> Arize, WhyLabs, Evidently AI</li></ul><h4 id="verification-for-animations" tabindex="-1">Verification for Animations <a class="header-anchor" href="#verification-for-animations" aria-label="Permalink to &quot;Verification for Animations&quot;">​</a></h4><p>Static tools capture moment-in-time state. Animations require specialized approaches:</p><ul><li><strong>Layer 1 (ms):</strong> Web Animations API&#39;s <code>getAnimations()</code> waits for completion before assertions</li><li><strong>Layer 2 (ms):</strong> PerformanceObserver measures CLS (Cumulative Layout Shift)</li><li><strong>Layer 3 (s):</strong> CI snapshot comparison with animations frozen via <code>animation: none !important</code></li><li><strong>Layer 4:</strong> Low-FPS frame capture (5fps) for multimodal agents to inspect frame sequences</li></ul><h3 id="_6-design-state-management-across-sessions" tabindex="-1">6. Design State Management Across Sessions <a class="header-anchor" href="#_6-design-state-management-across-sessions" aria-label="Permalink to &quot;6. Design State Management Across Sessions&quot;">​</a></h3><p>Agents lack memory between sessions—like shift workers with no handover.</p><p><strong>Standardize startup routine:</strong></p><ol><li>Verify working directory</li><li>Read Git log and progress file</li><li>Select next highest-priority task</li><li>Start dev server, sanity-check functionality</li></ol><p><strong>Use Git as the bridge:</strong> Commit with descriptive messages. The <code>git log --oneline -20</code> becomes the reliable &quot;what happened&quot; record, tied one-to-one with code changes and resistant to rot.</p><p><strong>Use JSON for progress records:</strong> JSON structure prevents agents from inappropriately editing feature lists compared to Markdown. For long projects, use the test suite itself as feature specification instead.</p><h3 id="_7-platform-specific-harness-strategies-codex-vs-claude-code" tabindex="-1">7. Platform-Specific Harness Strategies: Codex vs. Claude Code <a class="header-anchor" href="#_7-platform-specific-harness-strategies-codex-vs-claude-code" aria-label="Permalink to &quot;7. Platform-Specific Harness Strategies: Codex vs. Claude Code&quot;">​</a></h3><p>Research by Morph proves that harness design matters more than model selection. Swapping the harness changes SWE-bench scores by 22 points; swapping the model itself changes scores by only 1 point.</p><h4 id="architectural-differences" tabindex="-1">Architectural Differences <a class="header-anchor" href="#architectural-differences" aria-label="Permalink to &quot;Architectural Differences&quot;">​</a></h4><p><strong>Codex:</strong> &quot;Closed-room&quot; architecture. Brings code into cloud sandbox (network-isolated), works independently, returns diff. Enables asynchronous parallel task execution.</p><p><strong>Claude Code:</strong> &quot;Workshop-style.&quot; Enters developer environment directly, edits files locally. Hooks system enables deterministic control before/after tool execution.</p><h4 id="codex-specific-features" tabindex="-1">Codex-Specific Features <a class="header-anchor" href="#codex-specific-features" aria-label="Permalink to &quot;Codex-Specific Features&quot;">​</a></h4><ul><li>Cloud sandbox execution in network-isolated containers with parallelization</li><li>Async task queue (<code>codex cloud exec</code>) for parallel multi-task execution</li><li>Automations for scheduled tasks</li><li>App Server protocol unifying all client surfaces via JSON-RPC</li><li>Realtime steering to correct instructions mid-task</li><li>Agents SDK integration exposing Codex CLI as MCP server</li><li><strong>Hooks system (experimental, introduced March 26, 2026):</strong> Covers SessionStart, PreToolUse, PostToolUse, UserPromptSubmit, Stop. Pre/PostToolUse targets Bash only. Configuration goes in <code>~/.codex/hooks.json</code> or <code>&lt;repo&gt;/.codex/hooks.json</code>.</li></ul><p>Since Codex file operations execute through Bash, Bash-only Hooks provide practical coverage equivalent to Claude Code&#39;s file-operation matching, though less granular.</p><p>Windows support is temporarily disabled. The legacy <code>notify</code> hook faces deprecation.</p><h4 id="claude-code-specific-features" tabindex="-1">Claude Code-Specific Features <a class="header-anchor" href="#claude-code-specific-features" aria-label="Permalink to &quot;Claude Code-Specific Features&quot;">​</a></h4><ul><li>Stable Hooks system covering all tools (Write, Edit, MultiEdit, Bash)</li><li>PreToolUse blocking enforcement</li><li>PostToolUse quality loop with <code>additionalContext</code> injection</li><li>PreCompact hook protecting critical information before compaction</li><li>MCP Tool Search reducing context consumption up to 85%</li><li>Agent Teams (experimental) enabling direct communication between sessions</li><li>Plan Mode (40–60% token reduction) plus Extended Thinking for complex decisions</li></ul><h4 id="shared-harness-layer" tabindex="-1">Shared Harness Layer <a class="header-anchor" href="#shared-harness-layer" aria-label="Permalink to &quot;Shared Harness Layer&quot;">​</a></h4><p>Both platforms benefit from:</p><ul><li>AGENTS.md (AAIF standard, read by Codex/Cursor/Devin/Gemini CLI/GitHub Copilot)</li><li>Skills (SKILL.md, open standard)</li><li>MCP configuration</li><li>ADRs, linter settings, test suites</li></ul><p>For Claude Code, include AGENTS.md via <code>@AGENTS.md</code> reference in CLAUDE.md since AGENTS.md isn&#39;t loaded natively.</p><h4 id="hybrid-strategy" tabindex="-1">Hybrid Strategy <a class="header-anchor" href="#hybrid-strategy" aria-label="Permalink to &quot;Hybrid Strategy&quot;">​</a></h4><p>Many adopt hybrid approaches: Claude Code plans and designs → Codex executes in parallel → Claude Code reviews and polishes. Build the harness in Claude Code, then scale execution in Codex.</p><h2 id="anti-patterns-to-avoid" tabindex="-1">Anti-Patterns to Avoid <a class="header-anchor" href="#anti-patterns-to-avoid" aria-label="Permalink to &quot;Anti-Patterns to Avoid&quot;">​</a></h2><ol><li><strong>Relying only on prompts:</strong> &quot;Remember to write tests&quot; in instructions insufficient. Force execution with hooks</li><li><strong>Accumulating explanatory docs:</strong> Represent dependencies through type definitions/schemas and structural tests rather than README prose</li><li><strong>Bloating instruction files:</strong> Aim for under 50 lines, not 1,000+</li><li><strong>Building agent-only infrastructure:</strong> Build excellent developer infrastructure; agents benefit automatically</li><li><strong>Scaling without harness:</strong> Scaling agent count without quality infrastructure creates compounding debt, not leverage</li></ol><h2 id="minimum-viable-harness-mvh" tabindex="-1">Minimum Viable Harness (MVH) <a class="header-anchor" href="#minimum-viable-harness-mvh" aria-label="Permalink to &quot;Minimum Viable Harness (MVH)&quot;">​</a></h2><p>Build incrementally rather than adopting all principles simultaneously.</p><p><strong>Week 1:</strong></p><ul><li>Write AGENTS.md / CLAUDE.md (under 50 lines, pointers only)</li><li>Set up pre-commit hooks for linters/formatters/type checks</li><li>Configure PostToolUse Hook for auto-formatting</li><li>Write first ADR</li></ul><p><strong>Week 2–4:</strong></p><ul><li>Add test or linter rule whenever agent makes mistake</li><li>Establish plan → approve → execute workflow</li><li>Introduce E2E testing tool (Playwright CLI or agent-browser)</li><li>Make passing tests completion condition via Stop Hook</li><li>Standardize session startup routine</li></ul><p><strong>Month 2–3:</strong></p><ul><li>Build custom linters with fix instructions in error messages</li><li>Link ADRs and linter rules (archgate pattern)</li><li>Replace descriptive docs with tests and ADRs</li><li>Set up safety gates with PreToolUse Hooks</li></ul><p><strong>Month 3+:</strong></p><ul><li>Consider advanced patterns like Plankton</li><li>Introduce garbage-collection processes</li><li>Run multiple agents simultaneously</li><li>Measure harness effectiveness quantitatively</li></ul><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>Core insights:</p><ul><li>Enforce quality through mechanisms, not prompts. Linters, Hooks, tests, and ADRs compound in effectiveness</li><li>Push checks toward faster feedback layers: PostToolUse Hook (ms) &gt; pre-commit (s) &gt; CI (min) &gt; human review (h)</li><li>Build incrementally with MVH rather than adopting everything at once</li></ul><p>The field of harness engineering may have limited longevity as LLMs improve, but for March 2026 it remains essential for autonomous agent operation.</p><hr><h2 id="繁體中文全文摘要" tabindex="-1">繁體中文全文摘要 <a class="header-anchor" href="#繁體中文全文摘要" aria-label="Permalink to &quot;繁體中文全文摘要&quot;">​</a></h2><h3 id="核心命題-系統-而非模型-才是關鍵" tabindex="-1">核心命題：系統，而非模型，才是關鍵 <a class="header-anchor" href="#核心命題-系統-而非模型-才是關鍵" aria-label="Permalink to &quot;核心命題：系統，而非模型，才是關鍵&quot;">​</a></h3><p>Harness engineering = 持續改善 agent 指令檔案 + 啟用自我驗證的工具鏈。存在目的是穩定 agent 輸出並維持自主運作。</p><h3 id="原則一-repository-hygiene-設計好腐敗" tabindex="-1">原則一：Repository Hygiene（設計好腐敗） <a class="header-anchor" href="#原則一-repository-hygiene-設計好腐敗" aria-label="Permalink to &quot;原則一：Repository Hygiene（設計好腐敗）&quot;">​</a></h3><p>Agents 平等對待所有 repo 文字，缺乏判斷文件陳舊的直覺。</p><p><strong>應放入 repo 的內容</strong>：</p><ul><li>可執行 artifact（程式碼、測試、linter 設定、型別定義）</li><li>帶時間戳和狀態追蹤的 ADR（Architecture Decision Records）</li></ul><p><strong>不應放入的內容</strong>：</p><ul><li>系統現狀的散文說明</li><li>手寫 API 描述</li><li>文字版架構概覽</li></ul><p>測試比文件更有韌性：規格變成測試，違反時會大聲失敗，而非靜默腐敗。</p><h3 id="原則二-用確定性工具強制品質-hook-驅動" tabindex="-1">原則二：用確定性工具強制品質（Hook 驅動） <a class="header-anchor" href="#原則二-用確定性工具強制品質-hook-驅動" aria-label="Permalink to &quot;原則二：用確定性工具強制品質（Hook 驅動）&quot;">​</a></h3><p><strong>核心原則</strong>：「LLM 比傳統 linter 和格式化工具貴且慢。只要確定性工具能做的，就用它。」</p><p>在 CLAUDE.md 寫「執行 linter」vs. 透過 Hooks 自動執行 linter——前者「幾乎每次」成功，後者「每次無例外」。</p><h4 id="四種-hook-模式" tabindex="-1">四種 Hook 模式 <a class="header-anchor" href="#四種-hook-模式" aria-label="Permalink to &quot;四種 Hook 模式&quot;">​</a></h4><table tabindex="0"><thead><tr><th>模式</th><th>觸發點</th><th>作用</th></tr></thead><tbody><tr><td><strong>Safety Gates</strong></td><td>PreToolUse</td><td>阻擋 <code>rm -rf</code>、<code>drop table</code>，防止編輯敏感檔案</td></tr><tr><td><strong>Quality Loops</strong></td><td>PostToolUse</td><td>檔案編輯後自動跑 linter，注入結果讓 agent 自我修正</td></tr><tr><td><strong>Completion Gates</strong></td><td>Stop</td><td>允許 agent 完成前先跑測試驗證</td></tr><tr><td><strong>Observability</strong></td><td>各點</td><td>串流意圖和結果到監控系統</td></tr></tbody></table><p>PostToolUse Hook 正確用法：JSON 結構 + <code>hookSpecificOutput.additionalContext</code>（純 stdout 不會注入回饋）。</p><p><strong>阻擋 Linter 設定修改</strong>：PreToolUse hook 阻擋對 <code>.eslintrc</code>、<code>pyproject.toml</code> 的寫入，強制 agent 修復程式碼而非抑制 lint 錯誤。</p><h4 id="各語言-linter-推薦" tabindex="-1">各語言 Linter 推薦 <a class="header-anchor" href="#各語言-linter-推薦" aria-label="Permalink to &quot;各語言 Linter 推薦&quot;">​</a></h4><table tabindex="0"><thead><tr><th>語言</th><th>PostToolUse Hook 推薦</th><th>速度優勢</th></tr></thead><tbody><tr><td>TypeScript/JS</td><td>Oxlint + Biome</td><td>50-100x、10-25x 比 ESLint/Prettier 快</td></tr><tr><td>Python</td><td>Ruff</td><td>900+ 規則，Rust 實作，&lt;1 秒完成</td></tr><tr><td>Go</td><td>golangci-lint</td><td>50+ linter 並行，支援 <code>--fix</code></td></tr><tr><td>Rust</td><td>clippy（pedantic）</td><td>阻止 agent 用 <code>allow_attributes</code> 靜默 lint</td></tr></tbody></table><h4 id="lint-錯誤訊息格式-給-agent-用" tabindex="-1">Lint 錯誤訊息格式（給 Agent 用） <a class="header-anchor" href="#lint-錯誤訊息格式-給-agent-用" aria-label="Permalink to &quot;Lint 錯誤訊息格式（給 Agent 用）&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ERROR: [什麼錯了] [file:line]</span></span>
<span class="line"><span>WHY: [為什麼有這個規則，ADR 連結]</span></span>
<span class="line"><span>FIX: [具體修復步驟 + 程式碼範例]</span></span></code></pre></div><h4 id="反饋速度決定品質" tabindex="-1">反饋速度決定品質 <a class="header-anchor" href="#反饋速度決定品質" aria-label="Permalink to &quot;反饋速度決定品質&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ms  (PostToolUse Hook)  → 格式化自動跑</span></span>
<span class="line"><span>s   (Pre-commit hook)   → linter/型別檢查</span></span>
<span class="line"><span>min (CI/CD)             → 完整測試套件</span></span>
<span class="line"><span>h+  (人工 review)       → 最慢層</span></span></code></pre></div><p><strong>方向</strong>：把 CI 的 linter 移到 pre-commit；把 pre-commit 的檢查移到 PostToolUse Hook。</p><h3 id="原則三-agents-md-claude-md-設計為「指標」" tabindex="-1">原則三：AGENTS.md / CLAUDE.md 設計為「指標」 <a class="header-anchor" href="#原則三-agents-md-claude-md-設計為「指標」" aria-label="Permalink to &quot;原則三：AGENTS.md / CLAUDE.md 設計為「指標」&quot;">​</a></h3><p><strong>目標尺寸：50 行以下</strong>（官方建議 200 行是上限，不是目標）。</p><p>Claude Code 系統提示約有 50 條指令。100 行 CLAUDE.md 約產生 150 條總指令——接近效能降解閾值。積極壓縮。</p><p><strong>應包含</strong>：路由指令（「跑 <code>npm test</code>」）、禁令 + ADR 參照、最小 build/test/deploy 指令 <strong>應排除</strong>：系統狀態解釋（程式碼和測試才是權威）、技術棧描述（package.json 揭示）、詳細風格指南（委託給 linter）</p><h3 id="原則四-分離規劃與執行" tabindex="-1">原則四：分離規劃與執行 <a class="header-anchor" href="#原則四-分離規劃與執行" aria-label="Permalink to &quot;原則四：分離規劃與執行&quot;">​</a></h3><p>Agent 傾向「一次性」完成整個功能。明確指令一次一個功能，每個小建構塊完成後驗證，比試圖一次完成更有效。</p><h3 id="原則五-e2e-測試給-agent「眼睛」" tabindex="-1">原則五：E2E 測試給 Agent「眼睛」 <a class="header-anchor" href="#原則五-e2e-測試給-agent「眼睛」" aria-label="Permalink to &quot;原則五：E2E 測試給 Agent「眼睛」&quot;">​</a></h3><p>沒有可觀測性，agent 在編譯成功後就宣告「完成」。</p><p><strong>無障礙樹 vs 截圖</strong>：</p><ul><li><strong>無障礙樹</strong>：程式化互動、確定性測試、操作自動化</li><li><strong>截圖</strong>：視覺 bug 偵測、CSS/layout 問題、空間定位</li></ul><p><strong>Token 效率</strong>：agent-browser（Vercel Labs）比 Playwright MCP 省 5.7x tokens（6 個測試：5.5K vs 31K 字元）。</p><h3 id="codex-vs-claude-code-架構差異" tabindex="-1">Codex vs Claude Code 架構差異 <a class="header-anchor" href="#codex-vs-claude-code-架構差異" aria-label="Permalink to &quot;Codex vs Claude Code 架構差異&quot;">​</a></h3><table tabindex="0"><thead><tr><th>面向</th><th>Codex</th><th>Claude Code</th></tr></thead><tbody><tr><td>架構</td><td>「密室」—程式碼進雲端沙箱，回傳 diff</td><td>「工作坊」—直接進入開發環境本機編輯</td></tr><tr><td>並行</td><td>非同步任務佇列，<code>codex cloud exec</code></td><td>Agent Teams（實驗性）</td></tr><tr><td>Hooks</td><td>實驗性（2026-03-26 引入），僅 Bash</td><td>穩定，涵蓋所有工具</td></tr></tbody></table><p><strong>混合策略</strong>：Claude Code 規劃設計 → Codex 並行執行 → Claude Code review 潤飾。</p><h3 id="最小可行-harness-mvh-四週計劃" tabindex="-1">最小可行 Harness（MVH）四週計劃 <a class="header-anchor" href="#最小可行-harness-mvh-四週計劃" aria-label="Permalink to &quot;最小可行 Harness（MVH）四週計劃&quot;">​</a></h3><p><strong>第 1 週</strong>：AGENTS.md（&lt;50 行）+ pre-commit hooks + PostToolUse 自動格式化 + 第一個 ADR</p><p><strong>第 2-4 週</strong>：agent 每次犯錯就加規則/測試 + plan→approve→execute 工作流 + E2E 測試 + Stop Hook 把通過測試設為完成條件</p><p><strong>第 2-3 月</strong>：自訂 linter + ADR 與 linter 連結 + 替換描述性文件為測試和 ADR + Safety Gates</p><h3 id="五大反模式" tabindex="-1">五大反模式 <a class="header-anchor" href="#五大反模式" aria-label="Permalink to &quot;五大反模式&quot;">​</a></h3><ol><li>只依賴 prompt（「記得寫測試」不夠，用 Hook 強制執行）</li><li>累積說明性文件（用型別定義和結構測試表達依賴）</li><li>指令檔案膨脹（目標 &lt;50 行，不是 1,000+）</li><li>建立 agent 專用基礎設施（建立良好的開發者基礎設施；agent 自動受益）</li><li>沒有 harness 就擴展規模（增加 agent 數量而不建品質基礎設施 = 複利負債）</li></ol><hr><h2 id="評分摘要" tabindex="-1">評分摘要 <a class="header-anchor" href="#評分摘要" aria-label="Permalink to &quot;評分摘要&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>理由</th></tr></thead><tbody><tr><td>A. Workspace 可行動性</td><td>9/10</td><td>Repo hygiene 清單、4 種 Hook 模式、MVH 4 週計劃、5 個 anti-patterns 直接可執行</td></tr><tr><td>B. 創新性</td><td>8/10</td><td>Hooks 分類法（Safety/Quality/Completion/Observability）、回饋速度層級為首創</td></tr><tr><td>C. 證據品質</td><td>9/10</td><td>每語言 linter 工具推薦具體（Oxlint+Biome/Ruff/golangci-lint/clippy），ms→h+ 層級量化</td></tr><tr><td>D. 技術深度</td><td>9/10</td><td>非常實作導向：特定工具、反模式、4 週計劃、完整 hooks 設定範例</td></tr><tr><td>E. 泛化性</td><td>8/10</td><td>MVH 原則跨語言、跨 agent 平台適用</td></tr><tr><td><strong>加權總分</strong></td><td><strong>8.65/10</strong></td><td>9×0.3+8×0.2+9×0.2+9×0.15+8×0.15 = 2.7+1.6+1.8+1.35+1.2</td></tr></tbody></table><p><strong>整合決策</strong>：Rule<br><strong>整合位置</strong>：<code>.claude/refs/harness-design.md</code>（Hooks 分類法 + MVH 計劃）<br><strong>整合狀態</strong>：待實作</p>`,186)])])}const g=t(s,[["render",n]]);export{h as __pageData,g as default};
